  1→// web/components/dashboard/unified-feed.tsx
  2→"use client";
  3→
  4→import useSWR from "swr";
  5→import Link from "next/link";
  6→import {
  7→  projects as projectsApi,
  8→  releases as releasesApi,
  9→  sources as sourcesApi,
 10→  semanticReleases as srApi,
 11→} from "@/lib/api/client";
 12→import { VersionChip } from "@/components/ui/version-chip";
 13→import { getProviderIcon } from "@/components/ui/provider-badge";
 14→import { Sparkles } from "lucide-react";
 15→import type { Release, SemanticRelease, Source } from "@/lib/api/types";
 16→import { timeAgo } from "@/lib/format";
 17→import { useTranslation } from "@/lib/i18n/context";
 18→
 19→type FeedItemType =
 20→  | { kind: "release"; data: Release; repository?: string; provider?: string; projectName?: string }
 21→  | { kind: "semantic"; data: SemanticRelease; projectName?: string };
 22→
 23→function getTimestamp(item: FeedItemType): number {
 24→  if (item.kind === "release") {
 25→    return new Date(item.data.released_at ?? item.data.created_at).getTime();
 26→  }
 27→  return new Date(item.data.created_at).getTime();
 28→}
 29→
 30→function getTimeStr(item: FeedItemType): string {
 31→  if (item.kind === "release") {
 32→    return item.data.released_at ?? item.data.created_at;
 33→  }
 34→  return item.data.created_at;
 35→}
 36→
 37→function ProviderIcon({ provider }: { provider: string }) {
 38→  const icon = getProviderIcon(provider);
 39→  if (!icon) return <div className="h-3.5 w-3.5 shrink-0" />;
 40→  return icon({ size: 14, className: "shrink-0 text-text-muted" });
 41→}
 42→
 43→export function UnifiedFeed() {
 44→  const { t } = useTranslation();
 45→
 46→  const { data: projectsData } = useSWR("projects-for-dashboard", () =>
 47→    projectsApi.list()
 48→  );
 49→
 50→  const { data: feedItems, isLoading } = useSWR(
 51→    projectsData ? "unified-feed" : null,
 52→    async () => {
 53→      if (!projectsData?.data?.length) return [];
 54→
 55→      const projectMap = new Map(
 56→        projectsData.data.map((p) => [p.id, p.name])
 57→      );
 58→      const projectSlice = projectsData.data.slice(0, 10);
 59→
 60→      // Fetch releases, sources, and semantic releases in parallel
 61→      const [releaseResults, sourceResults, srResults] = await Promise.all([
 62→        Promise.all(
 63→          projectSlice.map((p) =>
 64→            releasesApi.listByProject(p.id, 1).catch(() => null)
 65→          )
 66→        ),
 67→        Promise.all(
 68→          projectSlice.map((p) =>
 69→            sourcesApi.listByProject(p.id, 1).catch(() => null)
 70→          )
 71→        ),
 72→        Promise.all(
 73→          projectSlice.map((p) =>
 74→            srApi.list(p.id, 1).catch(() => null)
 75→          )
 76→        ),
 77→      ]);
 78→
 79→      // Build source lookup maps
 80→      const sourceMap = new Map<string, string>();
 81→      const providerMap = new Map<string, string>();
 82→      const sourceProjectMap = new Map<string, string>();
 83→      sourceResults
 84→        .filter((r): r is NonNullable<typeof r> => r !== null)
 85→        .flatMap((r) => r.data)
 86→        .forEach((s: Source) => {
 87→          sourceMap.set(s.id, s.repository);
 88→          providerMap.set(s.id, s.provider);
 89→          sourceProjectMap.set(s.id, s.project_id);
 90→        });
 91→
 92→      // Build feed items
 93→      const items: FeedItemType[] = [];
 94→
 95→      releaseResults
 96→        .filter((r): r is NonNullable<typeof r> => r !== null)
 97→        .flatMap((r) => r.data)
 98→        .forEach((rel) => {
 99→          const projectId = sourceProjectMap.get(rel.source_id);
100→          items.push({
101→            kind: "release",
102→            data: rel,
103→            repository: sourceMap.get(rel.source_id),
104→            provider: providerMap.get(rel.source_id),
105→            projectName: projectId ? projectMap.get(projectId) : undefined,
106→          });
107→        });
108→
109→      srResults
110→        .filter((r): r is NonNullable<typeof r> => r !== null)
111→        .flatMap((r) => r.data)
112→        .forEach((sr) => {
113→          items.push({
114→            kind: "semantic",
115→            data: sr,
116→            projectName: projectMap.get(sr.project_id),
117→          });
118→        });
119→
120→      // Sort by timestamp descending, take first 15
121→      items.sort((a, b) => getTimestamp(b) - getTimestamp(a));
122→      return items.slice(0, 15);
123→    },
124→    { refreshInterval: 30_000 }
125→  );
126→
127→  if (isLoading) {
128→    return (
129→      <div
130→        className="rounded-lg bg-surface py-16 text-center border border-border"
131→      >
132→        <p
133→          className="text-text-secondary"
134→          style={{
135→            fontFamily: "var(--font-dm-sans)",
136→            fontSize: "13px",
137→          }}
138→        >
139→          {t("dashboard.feed.loading")}
140→        </p>
141→      </div>
142→    );
143→  }
144→
145→  if (!feedItems || feedItems.length === 0) {
146→    return null; // Empty state handled by parent
147→  }
148→
149→  return (
150→    <div
151→      className="flex flex-col rounded-lg bg-surface border border-border"
152→      style={{ height: "336px" }}
153→    >
154→      {/* Header */}
155→      <div
156→        className="flex items-center justify-between px-5 py-4 shrink-0 border-b border-border"
157→      >
158→        <p
159→          className="text-xs uppercase tracking-[0.08em] text-text-secondary"
160→          style={{
161→            fontFamily: "var(--font-dm-sans)",
162→            fontSize: "12px",
163→          }}
164→        >
165→          {t("dashboard.feed.recentActivity")}
166→        </p>
167→      </div>
168→
169→      {/* Feed items -- scrollable */}
170→      <div className="flex-1 overflow-y-auto">
171→        {feedItems.map((item, idx) => (
172→          <FeedEntry
173→            key={item.kind === "release" ? `r-${item.data.id}` : `sr-${item.data.id}`}
174→            item={item}
175→            isLast={idx === feedItems.length - 1}
176→          />
177→        ))}
178→      </div>
179→    </div>
180→  );
181→}
182→
183→function FeedEntry({ item, isLast }: { item: FeedItemType; isLast: boolean }) {
184→  const { t } = useTranslation();
185→
186→  if (item.kind === "semantic") {
187→    const sr = item.data;
188→    const urgency = sr.report?.urgency?.toUpperCase();
189→    const isUrgent = urgency === "CRITICAL" || urgency === "HIGH";
190→
191→    return (
192→      <Link
193→        href={`/projects/${sr.project_id}/semantic-releases/${sr.id}`}
194→        className="flex items-center gap-3 px-5 py-3 transition-colors hover:bg-background"
195→        style={{
196→          borderBottom: isLast ? undefined : "1px solid var(--border)",
197→        }}
198→      >
199→        {/* AI icon */}
200→        <Sparkles className="h-3.5 w-3.5 shrink-0 text-text-muted" />
201→
202→        {/* Content */}
203→        <div className="min-w-0 flex-1 flex items-center gap-2">
204→          <span
205→            className="truncate text-text-secondary"
206→            style={{
207→              fontFamily: "var(--font-dm-sans)",
208→              fontSize: "13px",
209→            }}
210→          >
211→            {item.projectName ?? t("dashboard.feed.unknownProject")}
212→          </span>
213→          {isUrgent && (
214→            <span
215→              className="inline-flex items-center rounded px-1 py-0.5 text-[10px] font-semibold leading-none"
216→              style={{
217→                backgroundColor: urgency === "CRITICAL" ? "#fff1f2" : "#fff8f0",
218→                color: urgency === "CRITICAL" ? "#dc2626" : "#d97706",
219→              }}
220→            >
221→              {urgency}
222→            </span>
223→          )}
224→        </div>
225→
226→        {/* Version + timestamp */}
227→        <div className="flex items-center gap-3 shrink-0">
228→          <VersionChip version={sr.version} />
229→          <span
230→            className="whitespace-nowrap text-text-muted"
231→            style={{
232→              fontFamily: "var(--font-dm-sans)",
233→              fontSize: "12px",
234→            }}
235→          >
236→            {timeAgo(getTimeStr({ kind: "semantic", data: sr }))}
237→          </span>
238→        </div>
239→      </Link>
240→    );
241→  }
242→
243→  // Raw release
244→  const release = item.data;
245→
246→  return (
247→    <Link
248→      href={`/releases/${release.id}`}
249→      className="flex items-center gap-3 px-5 py-3 transition-colors hover:bg-background"
250→      style={{
251→        borderBottom: isLast ? undefined : "1px solid var(--border)",
252→      }}
253→    >
254→      {/* Provider icon */}
255→      {item.provider ? (
256→        <ProviderIcon provider={item.provider} />
257→      ) : (
258→        <div className="h-3.5 w-3.5 shrink-0" />
259→      )}
260→
261→      {/* Content */}
262→      <div className="min-w-0 flex-1 flex items-center gap-2">
263→        <span
264→          className="truncate text-text-secondary"
265→          style={{
266→            fontFamily: "'JetBrains Mono', monospace",
267→            fontSize: "13px",
268→          }}
269→        >
270→          {item.repository ?? release.source_id.slice(0, 12)}
271→        </span>
272→        {item.projectName && (
273→          <span
274→            className="truncate text-text-muted"
275→            style={{
276→              fontFamily: "var(--font-dm-sans)",
277→              fontSize: "12px",
278→            }}
279→          >
280→            · {item.projectName}
281→          </span>
282→        )}
283→      </div>
284→
285→      {/* Version + timestamp */}
286→      <div className="flex items-center gap-3 shrink-0">
287→        <VersionChip version={release.version} />
288→        <span
289→          className="whitespace-nowrap text-text-muted"
290→          style={{
291→            fontFamily: "var(--font-dm-sans)",
292→            fontSize: "12px",
293→          }}
294→        >
295→          {timeAgo(release.released_at ?? release.created_at)}
296→        </span>
297→      </div>
298→    </Link>
299→  );
300→}
301→

  1→// web/app/page.tsx
  2→"use client";
  3→
  4→import { useEffect } from "react";
  5→import useSWR, { mutate } from "swr";
  6→import { StatsCards } from "@/components/dashboard/stats-cards";
  7→import { ReleaseTrendChart } from "@/components/dashboard/release-trend-chart";
  8→import { UnifiedFeed } from "@/components/dashboard/unified-feed";
  9→import { DashboardEmptyState } from "@/components/dashboard/empty-state";
 10→import { DiscoverySection } from "@/components/dashboard/discovery-section";
 11→import { SuggestionsSection } from "@/components/dashboard/suggestions-section";
 12→import { projects as projectsApi } from "@/lib/api/client";
 13→import { useAuth } from "@/lib/auth/context";
 14→import { useTranslation } from "@/lib/i18n/context";
 15→
 16→const SSE_BASE = process.env.NEXT_PUBLIC_API_URL || "/api/v1";
 17→
 18→export default function DashboardPage() {
 19→  const { user } = useAuth();
 20→  const { t } = useTranslation();
 21→  const { data: projectsData, isLoading } = useSWR("projects-for-dashboard", () =>
 22→    projectsApi.list()
 23→  );
 24→
 25→  // Listen to SSE events and revalidate dashboard data on new releases
 26→  useEffect(() => {
 27→    let es: EventSource | null = null;
 28→    let retryTimer: ReturnType<typeof setTimeout> | null = null;
 29→
 30→    function connect() {
 31→      try {
 32→        es = new EventSource(`${SSE_BASE}/events`);
 33→        es.onmessage = () => {
 34→          // Revalidate all dashboard SWR keys on any event
 35→          mutate((key) => typeof key === "string" && (
 36→            key === "stats" ||
 37→            key.startsWith("trend-") ||
 38→            key === "unified-feed"
 39→          ), undefined, { revalidate: true });
 40→        };
 41→        es.onerror = () => {
 42→          es?.close();
 43→          retryTimer = setTimeout(connect, 5000);
 44→        };
 45→      } catch {
 46→        retryTimer = setTimeout(connect, 5000);
 47→      }
 48→    }
 49→
 50→    connect();
 51→    return () => {
 52→      es?.close();
 53→      if (retryTimer) clearTimeout(retryTimer);
 54→    };
 55→  }, []);
 56→
 57→  const hasProjects = !isLoading && projectsData?.data && projectsData.data.length > 0;
 58→
 59→  return (
 60→    <div className="space-y-6">
 61→      <div>
 62→        <h1
 63→          style={{
 64→            fontFamily: "var(--font-fraunces)",
 65→            fontSize: "24px",
 66→            fontWeight: 700,
 67→            color: "var(--foreground)",
 68→          }}
 69→        >
 70→          {t("dashboard.title")}
 71→        </h1>
 72→        <p className="mt-1 text-[13px] text-text-secondary" style={{ fontFamily: "var(--font-dm-sans)" }}>
 73→          {t("dashboard.description")}
 74→        </p>
 75→      </div>
 76→
 77→      {user?.github_login && user.github_login !== "dev" ? (
 78→        <SuggestionsSection showAuthTabs />
 79→      ) : (
 80→        <>
 81→          <DiscoverySection />
 82→          <SuggestionsSection />
 83→        </>
 84→      )}
 85→
 86→      {hasProjects ? (
 87→        <>
 88→          <StatsCards />
 89→          <div className="grid gap-4 lg:grid-cols-2">
 90→            <ReleaseTrendChart />
 91→            <UnifiedFeed />
 92→          </div>
 93→        </>
 94→      ) : isLoading ? (
 95→        <div
 96→          className="py-16 text-center text-text-secondary"
 97→          style={{
 98→            fontFamily: "var(--font-dm-sans)",
 99→            fontSize: "13px",
100→          }}
101→        >
102→          {t("dashboard.loading")}
103→        </div>
104→      ) : (
105→        <DashboardEmptyState />
106→      )}
107→    </div>
108→  );
109→}
